<?php
namespace Database\Seeders;
use App\Models\CongratulationMessage;use App\Models\GuildUnion;use App\Models\User;use Illuminate\Database\Seeder;
class CongratulationMessageSeeder extends Seeder{public function run():void{$admin=User::first();$unions=GuildUnion::all()->values();$titles=['پیام تبریک روز اصناف','پیام تبریک سال نو','پیام تبریک هفته دولت','پیام تبریک افتتاح اتحادیه جدید','پیام مناسبتی مدیر اتحادیه'];foreach($titles as $i=>$title){$union=$unions->isNotEmpty()?$unions[$i%$unions->count()]:null;CongratulationMessage::updateOrCreate(['slug'=>'congratulation-message-'.($i+1)],['title'=>$title,'body'=>'<p>این پیام تبریک نمونه برای نمایش در صفحه اصلی و صفحه اتحادیه‌های مرتبط اتاق اصناف گرگان ایجاد شده است.</p>','manager_name'=>$union?->manager_name ?? 'رئیس اتاق اصناف','manager_position'=>$union?'رئیس '.$union->name:'رئیس اتاق اصناف گرگان','manager_image'=>'assets/img/asnaf-gorgan-default.jpg','union_id'=>$union?->id,'show_on_home'=>true,'show_on_union_page'=>true,'status'=>'published','published_at'=>now()->subDays($i),'created_by'=>$admin?->id,'approved_by'=>$admin?->id,'sort_order'=>$i+1,'is_active'=>true]);}}}
